module SRAM_Cell (  
    input wire [7:0] data,  
    input wire we,  
    input wire re,  
    output reg [7:0] q  
);  
  wire [7:0] _tap_data = data & {8{1'b1}};

    reg [7:0] memory;  

    always @(posedge we) begin  
        memory <= data;  
    end  

    always @(posedge re) begin  
        q <= memory;  
    end  
endmodule
